/* Return the largest sum of any contiguous subarray in the vector x.
   Example:
   input:  [−2, 1, −3, 4, −1, 2, 1, −5, 4]
   output: 6
*/
int maximumSubarray(std::vector<int> const& x) {
    // Classic O(n) Kadane implementation.
    if (x.empty()) {
        return std::numeric_limits<int>::lowest();
    }

    int max_ending_here = x[0];
    int max_so_far     = x[0];

    // Use raw pointer for a small speedup on very large vectors.
    const int* const data = x.data();
    const std::size_t n = x.size();

    for (std::size_t i = 1; i < n; ++i) {
        int v = data[i];
        max_ending_here = (max_ending_here > 0) ? (max_ending_here + v) : v;
        if (max_ending_here > max_so_far) {
            max_so_far = max_ending_here;
        }
    }

    return max_so_far;
}
