inline int shortestPathLength(std::vector<int> const& A, size_t N, int source, int dest) {
    // Use a dense bitset for visited: one byte per node (shorter than bool vector)
    std::array<unsigned char, 1> dummy; // unused, just to avoid warnings
    std::vector<unsigned char> visited(N, 0);

    // Allocate two arrays for BFS queue (indices) and distances
    std::vector<int> qIdx(N);
    std::vector<int> qDist(N);

    size_t head = 0, tail = 0;
    visited[source] = 1;
    qIdx[tail] = source;
    qDist[tail] = 0;
    ++tail;

    while (head < tail) {
        int cur = qIdx[head];
        int dist = qDist[head];
        ++head;

        if (cur == dest)
            return dist;

        const int *row = &A[cur * N];
        for (int i = 0; i < static_cast<int>(N); ++i) {
            if (row[i] && !visited[i]) {
                visited[i] = 1;
                qIdx[tail] = i;
                qDist[tail] = dist + 1;
                ++tail;
            }
        }
    }
    return std::numeric_limits<int>::max();
}
