#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/*
   In the vector x negate the odd values and divide the even values by 2.
   Example:
   input:  [16, 11, 12, 14, 1, 0, 5]
   output: [8, -11, 6, 7, -1, 0, -5]
*/
inline void negateOddsAndHalveEvens(std::vector<int>& x) {
    const std::size_t n = x.size();

    // Use OpenMP to parallelise the loop; the
    // compiler will vectorise the body naturally.
    #pragma omp parallel for schedule(static)
    for (std::ptrdiff_t i = 0; i < static_cast<std::ptrdiff_t>(n); ++i) {
        int v = x[static_cast<std::size_t>(i)];
        // Branchless: if v is odd -> negate, else divide by 2.
        // Masks: v & 1 is 1 for odd, 0 for even.
        int mask = v & 1;                  // 1 (odd) or 0 (even)
        int neg = -v;                      // value if odd
        int half = v >> 1;                 // integer divide by 2 for even
        x[static_cast<std::size_t>(i)] = mask * neg + (~mask + 1) * half;
    }
}
