    // Prepare per‑thread local counters to avoid contention.
    const int n_threads = omp_get_max_threads();
    std::vector<std::array<std::size_t, 256>> local(n_threads);
    for (auto &a : local) a.fill(0);

    // Parallel loop: each thread updates its own bucket array.
    #pragma omp parallel for schedule(static)
    for (std::size_t idx = 0; idx < image.size(); ++idx) {
        int val = image[idx];
        // Assumed 0 <= val <= 255, but guard just in case.
        if (val < 0 || val > 255) continue;
        int tid = omp_get_thread_num();
        local[tid][val] += 1;
    }

    // Reduce thread‑local counters into the final result.
    for (const auto &a : local) {
        for (std::size_t v = 0; v < 256; ++v) {
            bins[v] += a[v];
        }
    }
