/* ------------------------------------------------------------------ */
/*  Utility: test whether an integer is a power of two.               */
/*  The implementation is kept identical to the original for exact   */
/*  semantics.  The inline specifier encourages the compiler to inline. */
/* ------------------------------------------------------------------ */
inline bool isPowerOfTwo(int x) noexcept
{
    return (x > 0) && !(x & (x - 1));
}

/* ------------------------------------------------------------------ */
/*  Parallel mapping of isPowerOfTwo over a vector of integers.       */
/*  The result is written into the supplied mask vector.  The masks    */
/*  vector is assumed to have the same size as the input vector.      */
/* ------------------------------------------------------------------ */
inline void mapPowersOfTwo(const std::vector<int>& x, std::vector<bool>& mask)
{
    const std::size_t n = x.size();
    // Parallel loop; static schedule works well for regular workloads.
    #pragma omp parallel for schedule(static) if(n > 1)
    for (std::ptrdiff_t i = 0; i < static_cast<std::ptrdiff_t>(n); ++i)
    {
        mask[i] = isPowerOfTwo(x[static_cast<std::size_t>(i)]);
    }
}
