06_fft_dft:
```cpp
#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <omp.h>

#if !defined(M_PI)
#define M_PI 3.14159265358979323846
#endif

// Optimised brute‑force DFT for real input, using OpenMP and trigonometric recursion.
void dft(const std::vector<double> &x, std::vector<std::complex<double>> &output) {
    const std::size_t N = x.size();
    output.resize(N);
#pragma omp parallel for schedule(static)
    for (std::size_t k = 0; k < N; ++k) {
        // compute W_k = exp(-2πi * k / N) once
        const double angle_k = -2 * M_PI * k / N;
        const double w_real = std::cos(angle_k);
        const double w_imag = std::sin(angle_k);  // sin(-θ) = -sinθ

        std::complex<double> sum(0.0, 0.0);
        std::complex<double> w(1.0, 0.0); // current power of W_k
        for (std::size_t n = 0; n < N; ++n) {
            sum += x[n] * w;
            // multiply w by W_k using the recurrence w = w * W_k
            const double tmp_real = w.real() * w_real - w.imag() * w_imag;
            const double tmp_imag = w.real() * w_imag + w.imag() * w_real;
            w.real(tmp_real);
            w.imag(tmp_imag);
        }
        output[k] = sum;
    }
}
