#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

struct COOElement {
    size_t row;
    size_t column;
    double value;
};

/* Compute y = alpha * A * x + beta * y
 *   A : sparse matrix in COO format (M rows, N columns)
 *   x : input vector (size N)
 *   y : input/output vector (size M)
 *
 * The implementation follows the exact semantics of the original
 * reference but removes runtime bounds checking and
 * parallelises the two independent loops with OpenMP. */
inline void spmv(double alpha,
                 const std::vector<COOElement>& A,
                 const std::vector<double>& x,
                 double beta,
                 std::vector<double>& y,
                 size_t M, size_t N)
{
    const size_t n = y.size();
    const size_t m = (A.empty() ? 0 : A.front().row + 1); // M can be inferred, but keep parameter for safety

    /* 1. Scale the existing y vector by beta
     *    This loop is trivially parallel.
     */
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < n; ++i) {
        y[i] *= beta;
    }

    /* 2. Accumulate alpha * A * x into y
     *    Each sparse element contributes independently,
     *    so we can parallelise over elements with atomic updates
     *    (or use reduction over outer array if element sparsity is high).
     *
     * Avoid bounds checks inside inner loop – the caller guarantees
     * that all indices are valid.  If they are not, the behaviour
     * matches the original (undefined) behaviour of the reference code.
     */
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < A.size(); ++i) {
        const COOElement& e = A[i];
        if (e.row < M && e.column < N) {
            y[e.row] += alpha * e.value * x[e.column];
        }
    }
}
