/* Count how many strings in `s` start with each lowercase letter.
   The result is placed into `bins` (indices 0..25 → 'a'..'z').
   The implementation is fully parallel and preserves the exact
   behaviour of the original serial version. */
inline void firstLetterCounts(std::vector<std::string> const& s,
                              std::array<std::size_t, 26> &bins) {
    // Helper to zero the array, thread‑local
    const std::size_t ALPHA = 26;
    const std::size_t n = s.size();

    // Allocate per‑thread temporary bins to avoid atomic contention.
    // OMP guarantees that `thread_num` is non‑negative and < thread_limit.
    int const thread_limit = omp_get_max_threads();
    std::vector<std::array<std::size_t, 26>> local_bins(thread_limit);
    for (int t = 0; t < thread_limit; ++t)
        local_bins[t].fill(0);

    // Parallel loop with simple index based schedule to keep work
    // balanced and locality high.  No need for dynamic scheduling.
    #pragma omp parallel
    {
        int const t = omp_get_thread_num();
        auto &my_bins = local_bins[t];

        #pragma omp for schedule(static)
        for (std::size_t i = 0; i < n; ++i) {
            // Using a pointer improves cache locality for long strings.
            const char c = s[i].data()[0];
            const std::size_t idx = static_cast<std::size_t>(c - 'a');
            // Bounds are guaranteed by the problem statement.
            ++my_bins[idx];
        }
    }

    // Merge thread‑local bins into the final result.
    bins.fill(0);
    for (int t = 0; t < thread_limit; ++t) {
        for (std::size_t i = 0; i < ALPHA; ++i) {
            bins[i] += local_bins[t][i];
        }
    }
}
