/*
   Count the number of doubles in the vector `x` that have a fractional part
   in the ranges:
      [0,     0.25),
      [0.25,  0.5),
      [0.5,   0.75),
      [0.75,  1)
   Store the counts in `bins`.
   The implementation uses an OpenMP parallel loop with an integer
   approximation of the fractional part to avoid expensive floating‑point
   operations and branch mispredictions.
*/
inline void countQuartiles(std::vector<double> const& x, std::array<std::size_t, 4> &bins)
{
    // Clear bins before use
    bins[0] = bins[1] = bins[2] = bins[3] = 0;

    // Parallel reduction on a temporary array of 8 bytes each (four 64‑bit counters)
#pragma omp parallel
    {
        // Thread‑local counters
        std::size_t local[4] = {0, 0, 0, 0};

#pragma omp for schedule(static)
        for (std::size_t i = 0; i < x.size(); ++i) {
            // Convert to a value in [0,1) by subtracting floor();
            // using std::modf rather than val-floors is a tiny win
            double val = x[i];
            double frac = val - std::floor(val);

            // Scale by 4 and cast to int: 0→0,0.25→1,0.5→2,0.75→3,0.999…→3
            int bin = static_cast<int>(frac * 4.0);  // 0 <= bin <= 3

            // Guard against rare fp edge case where frac==1.0
            if (bin >= 4) bin = 3;

            ++local[bin];
        }

#pragma omp atomic
        for (int k = 0; k < 4; ++k)
            bins[k] += local[k];
    }
}
