#pragma once
#include <vector>
#include <cstdint>
#include <algorithm>
#include <numeric>
#include <omp.h>
#include <immintrin.h>

/* Return the sum of the minimum value at each index of vectors x and y for all indices.
   i.e. sum = min(x_0, y_0) + min(x_1, y_1) + min(x_2, y_2) + ...
   Example:
   input: x=[3, 4, 0, 2, 3], y=[2, 5, 3, 1, 7]
   output: 10
*/
int64_t sumOfMinimumElements(const std::vector<int64_t>& x, const std::vector<int64_t>& y)
{
    const std::size_t n = x.size();
    int64_t total = 0;

    // Parallel reduction with OpenMP
    #pragma omp parallel
    {
        int64_t local_sum = 0;

        // Work in chunks of 4 for AVX2 vectorization
        const std::size_t chunk = 4;
        std::size_t i = 0;

        // Main vectorized loop
        for (; i + chunk <= n; i += chunk)
        {
            __m256i ax = _mm256_loadu_si256(reinterpret_cast<const __m256i*>(&x[i]));
            __m256i by = _mm256_loadu_si256(reinterpret_cast<const __m256i*>(&y[i]));
            __m256i m  = _mm256_min_epi64(ax, by);
            // horizontal sum of 4 int64_t
            __m128i low  = _mm256_castsi256_si128(m);
            __m128i high = _mm256_extracti128_si256(m, 1);
            __m128i sum1 = _mm_add_epi64(low, high);
            __m128i sum2 = _mm_shuffle_epi32(sum1, _MM_SHUFFLE(2,3,0,1));
            __m128i sum4 = _mm_add_epi64(sum1, sum2);
            local_sum += _mm_cvtsi128_si64(sum4);
        }

        // Handle remaining elements
        for (; i < n; ++i)
            local_sum += std::min(x[i], y[i]);

        #pragma omp atomic
        total += local_sum;
    }

    return total;
}
