/* Compute the prefix sum of the vector x into output.
   Example:
   input: [1, 7, 4, 6, 6, 2]
   output: [1, 8, 12, 18, 24, 26]
*/
inline void prefixSum(const std::vector<long long>& x, std::vector<long long>& output)
{
    // Ensure the output vector has the correct size
    output.resize(x.size());

#if defined(_OPENMP)
    /* Parallel inclusive scan using OpenMP */
#pragma omp parallel
    {
        const std::size_t n = x.size();
        std::size_t chunk = (n + omp_get_num_threads() - 1) / omp_get_num_threads();
        std::size_t begin = omp_get_thread_num() * chunk;
        std::size_t end   = std::min(begin + chunk, n);

        if (begin == 0) {
            long long running = 0;
            for (std::size_t i = begin; i < end; ++i) {
                running += x[i];
                output[i] = running;
            }
        } else {
            // Each thread needs the sum of all previous chunks
            long long prev_sum = 0;
            for (std::size_t t = 0; t < omp_get_thread_num(); ++t) {
                std::size_t b = t * chunk;
                std::size_t e = std::min(b + chunk, n);
                for (std::size_t i = b; i < e; ++i) prev_sum += x[i];
            }
            long long running = prev_sum;
            for (std::size_t i = begin; i < end; ++i) {
                running += x[i];
                output[i] = running;
            }
        }
    }
#else
    /* Use the parallel inclusive_scan from the standard library when available */
    std::inclusive_scan(std::execution::par_unseq, x.begin(), x.end(), output.begin());
#endif
}
