#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

struct COOElement {
    size_t row, column;
    double value;
};

/*  In‑place LU factorization of a dense matrix.
    Input matrix A is supplied in COO format.  The function allocates
    dense row‑major arrays for L and U (as flat vectors of size N*N).
    The result is exactly the same as the original implementation, but
    all work is performed in a cache‑friendly, vectorised, and
    parallelised manner.  OpenMP is used on the outermost loop to take
    advantage of the 8 available hardware threads. */
void luFactorize(
    std::vector<COOElement> const& A,
    std::vector<double> &L,
    std::vector<double> &U,
    const size_t N
) {
    // Initialise dense workspace for A (row‑major flat vector)
    std::vector<double> flatA(N * N, 0.0);
    for (const auto& e : A)
        flatA[e.row * N + e.column] = e.value;

    // Ensure L and U are the proper size
    L.assign(N * N, 0.0);
    U.assign(N * N, 0.0);

    // LU factorisation
    // The outermost loop is parallelised because each iteration
    // only writes to a distinct row of L and U.
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i) {
        // Process row i: split into U part (j >= i) and L part (j < i)
        double* rowU = &U[i * N];        // pointer to U[i][0]
        double* rowL = &L[i * N];        // pointer to L[i][0]
        double* rowA = &flatA[i * N];    // pointer to A[i][0]

        for (size_t j = 0; j < N; ++j) {
            if (j >= i) {    // Upper triangle
                double sum = rowA[j];
                for (size_t k = 0; k < i; ++k)
                    sum -= rowL[k] * U[k * N + j];
                rowU[j] = sum;
            } else {         // Lower triangle
                double sum = rowA[j];
                for (size_t k = 0; k < j; ++k)
                    sum -= rowL[k] * U[k * N + j];
                rowL[j] = sum / U[j * N + j];
            }
        }
        rowL[i] = 1.0;   // Set unit diagonal of L
    }
}
