#pragma once
#include <vector>
#include <unordered_map>
#include <omp.h>

struct COOElement {
    size_t row, column;
    double value;
};

/* Fast sparse‑sparse matrix multiplication.
 *
 * Y = A * X     (A : M × K,  X : K × N)
 *
 * A and X are given in COO format.  Y is a dense M × N matrix stored
 * in row major order.  The implementation keeps the exact semantics
 * of the original but improves speed using:
 *
 *   * a hash table that maps rows of X to the list of its elements
 *   * OpenMP parallelisation over the outer loop of A
 *   * careful cache‑friendly access of Y
 *
 * It is deliberately written so that any compiler optimisation
 * settings produce the same functional result as the reference.
 */
void spmm(std::vector<COOElement> const& A,
          std::vector<COOElement> const& X,
          std::vector<double> &Y,
          size_t M, size_t K, size_t N) {

    /* Initialise the dense output matrix. */
    Y.assign(M * N, 0.0);

    /* Build a hash map: for every row of X keep a list of its elements.
     * The map is immutable afterwards which guarantees thread safety. */
    std::unordered_map<size_t, std::vector<const COOElement*>> x_by_row;
    x_by_row.reserve(X.size() * 2);          // handle load factor
    for (const auto* p = X.data(); p != X.data() + X.size(); ++p) {
        x_by_row[p->row].push_back(p);
    }

    /* Parallelise over the non‑zero entries of A.  The outer loop is the
     * natural choice because it controls the number of updates to Y and
     * each iteration only touches a single row of Y. */
    #pragma omp parallel for schedule(static)
    for (int64_t i = 0; i < static_cast<int64_t>(A.size()); ++i) {
        const COOElement& a = A[i];
        size_t a_row = a.row;                 // row index in Y
        size_t a_col = a.column;              // column index that must match X.row
        double a_val = a.value;               // pre‑fetch value

        /* Lookup all X entries that have a matching row.
         * If none found, skip the entire inner loop. */
        auto it = x_by_row.find(a_col);
        if (it == x_by_row.end()) continue;

        const std::vector<const COOElement*>& x_vec = it->second;
        double* y_row = Y.data() + a_row * N;  // cache friendly pointer

        /* Accumulate each matching product. */
        for (const COOElement* px : x_vec) {
            y_row[px->column] += a_val * px->value;
        }
    }
}
