/* Count the number of cartesian points in each quadrant.
   The vector points contains a list of `Point` objects.
   Store the counts in `bins`.
   Example:
   input: [{x=1.5, y=0.1}, {x=-3, y=1.1}, {x=5, y=9},
           {x=1.5, y=-1}, {x=3, y=-7}, {x=0.1, y=2}]
   output: [3, 1, 0, 2]
*/
void countQuadrants(std::vector<Point> const& points,
                    std::array<std::size_t, 4> &bins)
{
    // initialize bins
    bins[0] = bins[1] = bins[2] = bins[3] = 0;

    // OpenMP reduction using a local array per thread
    std::vector<std::array<std::size_t, 4>> localBins;
    localBins.resize(omp_get_max_threads());

    #pragma omp parallel
    {
        int tid = omp_get_thread_num();
        auto &l = localBins[tid];

        #pragma omp for
        for(std::size_t i = 0; i < points.size(); ++i) {
            const Point &p = points[i];

            // Branchless quadrant determination
            bool p_x_pos = p.x >= 0.0;
            bool p_y_pos = p.y >= 0.0;

            // Compute quadrant index: 0=Q1,1=Q2,2=Q3,3=Q4
            // Using bit operations: ((not p_x_pos)<<0) | ((not p_y_pos)<<1)
            unsigned int idx = (p_x_pos << 1) | p_y_pos; // mapping: (0,0)->0, (0,1)->1, (1,0)->2, (1,1)->3
            // Adjust mapping to match required ordering: Q1(>=0,>=0)->0, Q2(<0,>=0)->1, Q3(<0,<0)->2, Q4(>=0,<0)->3
            // Current idx gives: 0: (x>=0,y>=0), 1: (x<0,y>=0), 2: (x>=0,y<0), 3: (x<0,y<0)
            // So swap 2 and 3
            if(idx == 2) idx = 3;
            else if(idx == 3) idx = 2;

            ++l[idx];
        }
    }

    // Aggregate results
    for(const auto &l : localBins) {
        bins[0] += l[0];
        bins[1] += l[1];
        bins[2] += l[2];
        bins[3] += l[3];
    }
}
