/* Vector x contains values between 0 and 100, inclusive.
   Count the number of values in [0,10), [10, 20), [20, 30), ... and
   store the counts in `bins`.
   Example:
   input: [7, 32, 95, 12, 39, 32, 11, 71, 70, 66]
   output: [1, 2, 0, 3, 0, 0, 1, 2, 0, 1]
*/
inline void binsBy10Count(std::vector<double> const& x, std::array<size_t, 10> &bins) {
    // Reset result array
    for (auto &v : bins) v = 0;

#ifdef _OPENMP
    // Number of threads available
    int nthreads = omp_get_max_threads();
    // Allocate per-thread local bins
    std::vector<std::array<size_t,10>> localBins(nthreads);
    for (int t = 0; t < nthreads; ++t) {
        for (auto &v : localBins[t]) v = 0;
    }

    #pragma omp parallel
    {
        int tid = omp_get_thread_num();
        size_t start = (x.size() * tid) / nthreads;
        size_t end   = (x.size() * (tid + 1)) / nthreads;

        // Local counting
        for (size_t i = start; i < end; ++i) {
            size_t bin = static_cast<size_t>(x[i] / 10.0);
            // Clamp to [0,9] just in case of rounding edge
            if (bin > 9) bin = 9;
            ++localBins[tid][bin];
        }
    }

    // Merge local counts into the result
    for (int t = 0; t < nthreads; ++t) {
        for (size_t b = 0; b < 10; ++b) {
            bins[b] += localBins[t][b];
        }
    }
#else
    // Fallback single-threaded version
    for (size_t i = 0; i < x.size(); ++i) {
        size_t bin = static_cast<size_t>(x[i] / 10.0);
        if (bin > 9) bin = 9;
        ++bins[bin];
    }
#endif
