#pragma once
#include <vector>
#include <atomic>
#include <stack>
#include <cstddef>
#include <omp.h>

using Adj = std::vector<int>;
using Size = std::size_t;

/* Count connected components in an undirected graph defined by the adjacency matrix `A`.
   `A` is an N×N zero/one matrix stored row‑major.
   The implementation is parallel: each component is explored by a single thread,
   and the outer loop is distributed with OpenMP. */
int componentCount(const Adj& A, Size N)
{
    // Use atomic bools for thread-safe marking.
    std::vector<std::atomic_bool> visited(N);
    for (auto& v : visited) v.store(false, std::memory_order_relaxed);

    std::atomic_int comps{0};

    // Parallel outer loop. Each thread will pick an unvisited node,
    // mark it and perform a depth‑first search on its component.
    #pragma omp parallel for schedule(static)
    for (int ii = 0; ii < (int)N; ++ii)
    {
        // Try to claim node ii. If it was already visited by another thread,
        // this iteration does nothing.
        bool expected = false;
        if (!visited[ii].compare_exchange_strong(expected, true,
                                                 std::memory_order_acquire,
                                                 std::memory_order_relaxed))
            continue;                     // already processed by another thread

        // Stack for DFS. Each component is processed completely by this
        // thread; no further synchronization is needed after the stack empties.
        std::stack<int> st;
        st.push(ii);

        while (!st.empty())
        {
            int v = st.top();
            st.pop();

            // Scan row v to find neighbors.
            for (Size j = 0; j < N; ++j) {
                if (A[v * N + j] == 1)
                {
                    bool exp = false;
                    if (visited[j].compare_exchange_strong(exp, true,
                                                       std::memory_order_acquire,
                                                       std::memory_order_relaxed))
                    {
                        st.push((int)j);
                    }
                }
            }
        }

        // One component finished.
        comps.fetch_add(1, std::memory_order_relaxed);
    }

    return comps.load(std::memory_order_relaxed);
}
