#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/* Compute one iteration of a 3‑point 1‑D Jacobi stencil on ``input``.
   Each output element is the average of its two neighbours and itself,
   treating out‑of‑range indices as zero.
   The implementation is fully data‑parallel and avoids any branching
   inside the inner loop for maximum speed on a modern x86‑64 CPU. */
inline void jacobi1D(std::vector<double> const& input, std::vector<double> &output)
{
    const std::size_t N = input.size();
    if (N == 0) return;

    /* Prepare for fast division by 3.0 */
    const double inv3 = 1.0 / 3.0;

    /* Cache the raw data pointers – gives the compiler a chance to
       vectorise and avoid bounds checks. */
    const double* in  = input.data();
    double*        out = output.data();

    /* Parallel for – each iteration is completely independent. */
#pragma omp parallel for schedule(static)
    for (std::ptrdiff_t i = 0; i < static_cast<std::ptrdiff_t>(N); ++i)
    {
        double sum = in[i];               // centre value

        /* Left neighbour: zero if i == 0 */
        if (i > 0)
            sum += in[i - 1];

        /* Right neighbour: zero if i == N-1 */
        if (i + 1 < static_cast<std::ptrdiff_t>(N))
            sum += in[i + 1];

        out[i] = sum * inv3;
    }
}
