/*
 * Find the k-th smallest element of the vector `x`.
 * k is 1‑based (k=1 returns the minimum).
 * The original vector is not modified.
 *
 * Example:
 *   x = {1, 7, 6, 0, 2, 2, 10, 6}, k = 4 → returns 6
 */
inline int findKthSmallest(const std::vector<int>& x, int k) {
    if (k < 1 || k > static_cast<int>(x.size())) {
        throw std::out_of_range("k is out of bounds");
    }

    // Copy to avoid modifying the original vector
    std::vector<int> copy(x);
    std::nth_element(copy.begin(), copy.begin() + (k - 1), copy.end());
    return copy[k - 1];
