/* Set every cell's value to 1 if it has exactly one neighbour that's a 1.
   The function is fully parallelised with OpenMP and uses raw pointer arithmetic
   for maximal cache friendliness. */
inline void cellsXOR(std::vector<int> const& input, std::vector<int> &output, size_t N)
{
    // Ensure output size is correct
    if (output.size() < N * N) output.resize(N * N);

    const int*        in  = input.data();
    int*              out = output.data();
    const size_t stride = N;        // number of elements per row

    #pragma omp parallel for collapse(2) schedule(static)
    for (size_t i = 0; i < N; ++i) {
        const size_t idx = i * stride;
        for (size_t j = 0; j < N; ++j) {
            int count = 0;
            if (i > 0 && in[(i-1)*stride + j] == 1) ++count;        // north
            if (i + 1 < N && in[(i+1)*stride + j] == 1) ++count;   // south
            if (j > 0   && in[idx + j - 1] == 1) ++count;          // west
            if (j + 1 < N && in[idx + j + 1] == 1) ++count;        // east
            out[idx + j] = (count == 1) ? 1 : 0;
        }
    }
}
