/*
   Return the distance between the closest two elements in the vector x.
   The algorithm sorts the vector and then scans once, achieving O(n log n)
   time while using OpenMP to parallelise the reduction over independent
   chunks of the data.
*/
double closestPair(std::vector<double> const& x) {
    // Need at least two elements
    if (x.size() < 2)
        return 0.0;

    // Copy and sort the data locally – sorting is done serially,
    // but the subsequent linear scan can be parallelised.
    std::vector<double> sorted(x.begin(), x.end());
    std::sort(sorted.begin(), sorted.end());

    // Parallel reduction: each thread finds a local minimum over a chunk
    // of the sorted array, then a global minimum is computed.
    const size_t n = sorted.size();
    double global_min = std::numeric_limits<double>::max();

    #pragma omp parallel
    {
        double local_min = std::numeric_limits<double>::max();
        #pragma omp for schedule(static)
        for (size_t i = 0; i + 1 < n; ++i) {
            double d = sorted[i + 1] - sorted[i];   // non‑negative after sort
            if (d < local_min) local_min = d;
        }
        #pragma omp critical
        if (local_min < global_min) global_min = local_min;
    }

    return global_min;
}
