// ------------------------------------------------------------
// Optimized implementation: O(N³) brute‑force with
//   * 5‑line Lean kernel
//   * parallelisation of the outermost loop
//   * local minima per thread
//
// Assumes GCC + OpenMP 8 threads, compiled with -O2 -fopenmp
//
// ------------------------------------------------------------
inline double triangleAreaLoO(Point const& a, Point const& b, Point const& c)
{
    // Use a 64‑bit integer for the cross product when possible
    long double cross = static_cast<long double>(a.x) * (b.y - c.y)
                      + static_cast<long double>(b.x) * (c.y - a.y)
                      + static_cast<long double>(c.x) * (a.y - b.y);
    return 0.5L * std::fabsl(cross);
}

inline double smallestArea(const std::vector<Point>& points)
{
    const std::size_t n = points.size();
    if (n < 3) return 0.0;

    // Allocate local minima for each thread
    const int       maxThreads = omp_get_max_threads();
    std::vector<double> localMin(maxThreads, std::numeric_limits<double>::max());

#pragma omp parallel
    {
        const int  tid   = omp_get_thread_num();
        double&    local = localMin[tid];

        // Parallelise outer loop using static scheduling for load balance
#pragma omp for schedule(static)
        for (std::size_t i = 0; i < n - 2; ++i) {
            const Point& a = points[i];
            for (std::size_t j = i + 1; j < n - 1; ++j) {
                const Point& b = points[j];
                for (std::size_t k = j + 1; k < n; ++k) {
                    const double area = triangleAreaLoO(a, b, points[k]);
                    if (area < local) local = area;
                }
            }
        }
    }

    // Reduce per‑thread minima to a single result
    return *std::min_element(localMin.begin(), localMin.end());
}
