#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/* Compute one iteration of a 5‑point 2‑D Jacobi stencil.
   Input and output are N×N grids stored in row‑major order.
   The result is written to *output*, preserving the exact numerical
   behaviour of the reference implementation. */
void jacobi2D(std::vector<double> const& input,
              std::vector<double>& output,
              size_t N) noexcept
{
    const double inv5 = 0.2;                // 1.0 / 5.0
    const size_t stride = N;
    const double*  in  = input.data();
    double*        out = output.data();

    /* Parallelise over rows.  Each thread works on a disjoint set of
       output rows, so no false sharing or data races occur. */
    #pragma omp parallel for schedule(static)
    for (long long i = 0; i < static_cast<long long>(N); ++i) {
        const long long row = i * stride;
        const long long prev_row = (i > 0)   ? (row - stride) : -1;
        const long long next_row = (i + 1 < static_cast<long long>(N))
                                   ? (row + stride) : -1;

        for (long long j = 0; j < static_cast<long long>(N); ++j) {
            double sum = 0.0;

            /* centre element */
            sum += in[row + j];

            /* up */
            if (prev_row >= 0) sum += in[prev_row + j];

            /* down */
            if (next_row >= 0) sum += in[next_row + j];

            /* left */
            if (j > 0) sum += in[row + j - 1];

            /* right */
            if (j + 1 < static_cast<long long>(N)) sum += in[row + j + 1];

            out[row + j] = sum * inv5;      // divide by 5
        }
    }
}
