#include <cmath>
#include <cstdint>
#include <omp.h>

#if !defined(M_PI)
#   define M_PI 3.14159265358979323846
#endif

/*  Radix‑2, iterative Cooley‑Tukey FFT.
 *  The implementation keeps the original semantics
 *  (in‑place DFT) but is substantially faster on
 *  modern x86‑64 CPUs.  OpenMP is used to parallelise
 *  the work per stage.
 */
inline void fft(std::vector<std::complex<double>> const& x,
                std::vector<std::complex<double>>& output)
{
    const std::size_t N = x.size();
    output = x;                     // copy to output
    if (N <= 1) return;

    /* -----  bit‑reversal permutation  ----- */
    const std::size_t log2N = static_cast<std::size_t>(std::lround(std::log2(N)));
    for (std::size_t i = 0; i < N; ++i) {
        std::size_t j = i;
        for (std::size_t k = 1; k < log2N; k <<= 1)
            j = (j & ~(k << 1)) | ((j >> 1) & k);
        if (j > i) std::swap(output[i], output[j]);
    }

    /* -----  pre‑compute twiddle factors  ----- */
    std::vector<std::complex<double>> twiddle(N >> 1);
    const double PI = M_PI;
    for (std::size_t i = 0; i < (N >> 1); ++i)
        twiddle[i] = std::polar(1.0, -2.0 * PI * i / N);

    /* -----  iterative Cooley‑Tukey stages  ----- */
    for (std::size_t stage = 1, step = 2; stage <= log2N; ++stage, step <<= 1) {
        const std::size_t half = step >> 1;
        const std::size_t mult = N / step;
        #pragma omp for schedule(static)
        for (std::size_t k = 0; k < half; ++k) {
            const std::complex<double> w = twiddle[k * mult];
            for (std::size_t j = k; j < N; j += step) {
                const std::size_t l = j + half;
                const std::complex<double> t = w * output[l];
                output[l] = output[j] - t;
                output[j] += t;
            }
        }
    }
}
