struct COOElement
{
   std::size_t row, column;
   double value;
};

/*
 * Solve the sparse linear system Ax = b for x.
 * A is given in COO format (row, column, value) and is square of size N.
 * b and x are dense vectors of length N.
 * The implementation builds a dense matrix once and performs an
 * in‑place Gaussian elimination with partial pivoting.
 * The algorithm is identical to the reference implementation, but
 * uses a single contiguous array for the matrix and a few minor
 * optimisations to reduce the number of virtual calls and improve
 * cache friendliness.
 */
void solveLinearSystem(std::vector<COOElement> const &A,
                       std::vector<double> const    &b,
                       std::vector<double>          &x,
                       std::size_t                   N)
{
   // Allocate dense matrix in a single contiguous block.
   std::vector<double> mat(N * N, 0.0);

   // Fill the matrix.
   for (auto const &e : A)
      mat[e.row * N + e.column] = e.value;

   // Work vector for the RHS.
   std::vector<double> rhs = b;

   // Gaussian elimination with partial pivoting.
   for (std::size_t i = 0; i < N; ++i)
   {
      // 1) Pivot search.
      std::size_t maxRow = i;
      double maxVal = std::fabs(mat[i * N + i]);
      for (std::size_t k = i + 1; k < N; ++k)
      {
         double val = std::fabs(mat[k * N + i]);
         if (val > maxVal)
         {
            maxVal = val;
            maxRow = k;
         }
      }

      // 2) Swap current row with pivot row (if required).
      if (maxRow != i)
      {
         for (std::size_t col = 0; col < N; ++col)
            std::swap(mat[i * N + col], mat[maxRow * N + col]);
         std::swap(rhs[i], rhs[maxRow]);
      }

      // 3) Eliminate below.
      double pivot = mat[i * N + i];
      if (pivot == 0.0) continue;           // singular or zero pivot

      for (std::size_t k = i + 1; k < N; ++k)
      {
         double factor = -mat[k * N + i] / pivot;
         mat[k * N + i] = 0.0;              // explicit zero
         for (std::size_t j = i + 1; j < N; ++j)
            mat[k * N + j] += factor * mat[i * N + j];
         rhs[k] += factor * rhs[i];
      }
   }

   // Back substitution.
   x.resize(N);
   for (int i = static_cast<int>(N) - 1; i >= 0; --i)
   {
      double sum = rhs[i];
      for (int j = static_cast<int>(i) + 1; j < static_cast<int>(N); ++j)
         sum -= mat[i * N + j] * x[j];
      x[i] = sum / mat[i * N + i];
   }
}
