/*
   For each value in the vector `x` compute its index in the sorted vector.
   Store the results in `ranks_`.

   Example:
   input  : [3.1, 2.8, 9.1, 0.4, 3.14]
   output : [2, 1, 4, 0, 3]
   input  : [100, 7.6, 16.1, 18, 7.6]
   output : [4, 0, 1, 2, 3]
*/
inline void ranks(std::vector<float> const& x, std::vector<size_t> &ranks_) {
    const std::size_t n = x.size();

    // Allocate indices array
    std::vector<size_t> indices(n);
    std::iota(indices.begin(), indices.end(), 0);

    // Parallel sort of indices by the corresponding values in `x`
    // The custom comparator must be thread‑safe. Since it only reads
    // from `x`, which is const, it is safe for concurrent execution.
    std::sort(indices.begin(), indices.end(),
              [&x](size_t i1, size_t i2) { return x[i1] < x[i2]; });

    // Fill the result array. This loop is trivially parallel but the
    // work is very small compared to the sorting overhead, so a single
    // pass is sufficient and keeps the code simple.
    for (std::size_t i = 0; i < n; ++i) {
        ranks_[indices[i]] = i;
    }
}
