/* Return true if `val` is only in one of the vectors x or y.
   Return false if it is in both or neither.
   The implementation scans each vector only once, returning as soon
   as a definitive answer is found.
*/
inline bool xorContains(const std::vector<int>& x,
                        const std::vector<int>& y,
                        int val) noexcept
{
    bool foundInX = false, foundInY = false;

    // Scan x first; stop early if both found.
    for (std::size_t i = 0; i < x.size(); ++i) {
        if (x[i] == val) {
            foundInX = true;
            if (foundInY) return false;   // both found
            // If only one side can contain, we need to check y still
        }
    }

    // Scan y only if still undecided.
    for (std::size_t i = 0; i < y.size(); ++i) {
        if (y[i] == val) {
            if (foundInX) return false;  // both found
            foundInY = true;
        }
    }

    return foundInX ^ foundInY;
}
