#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <cstdint>
#include <algorithm>
#include <omp.h>

inline uint32_t bit_reverse(uint32_t v, uint32_t logn) {
    v = ((v & 0xaaaaaaaau) >> 1) | ((v & 0x55555555u) << 1);
    v = ((v & 0xccccccccu) >> 2) | ((v & 0x33333333u) << 2);
    v = ((v & 0xf0f0f0f0u) >> 4) | ((v & 0x0f0f0f0fu) << 4);
    v = ((v & 0xff00ff00u) >> 8) | ((v & 0x00ff00ffu) << 8);
    v = ((v >> 16) | (v << 16)) >> (32 - logn);
    return v;
}

void fftConjugate(std::vector<std::complex<double>>& x) {
    const std::size_t N = x.size();
    const uint32_t logN = static_cast<uint32_t>(std::log2(N));
    std::vector<std::complex<double>> twiddle(N/2);
    const double pi = M_PI;
    // pre‑compute twiddle factors
    double theta = -pi / (N/2);
    for (std::size_t k = 0; k < N/2; ++k)
        twiddle[k] = std::exp(std::complex<double>(0.0, theta * k));

    // radix‑2 decimation‑in‑time butterfly
    for (uint32_t s = 1; s <= logN; ++s) {
        const std::size_t m = 1ULL << s;          // butterfly size
        const std::size_t m2 = m >> 1;           // half size
        const std::complex<double>* tw = twiddle.data();
        std::size_t step = N / m;
        #pragma omp parallel for schedule(static)
        for (std::size_t j = 0; j < m2; ++j) {
            const std::complex<double> w = tw[j * step];
            for (std::size_t k = j; k < N; k += m) {
                const std::size_t t = k + m2;
                std::complex<double> temp = x[k] - x[t];
                x[k] += x[t];
                x[t] = temp * w;
            }
        }
    }

    // bit‑reversal permutation
    for (std::size_t i = 0; i < N; ++i) {
        std::size_t j = bit_reverse(static_cast<uint32_t>(i), logN);
        if (j > i) std::swap(x[i], x[j]);
    }

    // conjugate all elements
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i) {
        x[i] = std::conj(x[i]);
    }
}
