#pragma once
#include <vector>
#include <algorithm>
#include <limits>
#include <cmath>

struct Point {
    double x, y;
};

static inline double dist_sq(const Point &a, const Point &b) {
    double dx = a.x - b.x;
    double dy = a.y - b.y;
    return dx * dx + dy * dy;
}

// Recursive helper that returns the squared minimum distance
static double closest_pair_rec(std::vector<Point> &sorted_by_x,
                               std::vector<Point> &buffer,
                               size_t left, size_t right) {
    size_t n = right - left;
    if (n <= 3) {   // brute force
        double best = std::numeric_limits<double>::max();
        for (size_t i = left; i < right; ++i)
            for (size_t j = i + 1; j < right; ++j)
                best = std::min(best, dist_sq(sorted_by_x[i], sorted_by_x[j]));
        std::sort(sorted_by_x.begin() + left, sorted_by_x.begin() + right,
                  [](const Point &a, const Point &b){ return a.y < b.y; });
        return best;
    }

    size_t mid = (left + right) / 2;
    double mid_x = sorted_by_x[mid].x;

    double d_left  = closest_pair_rec(sorted_by_x, buffer, left,  mid);
    double d_right = closest_pair_rec(sorted_by_x, buffer, mid, right);
    double d = std::min(d_left, d_right);

    // Merge the two halves sorted by y
    std::merge(sorted_by_x.begin() + left, sorted_by_x.begin() + mid,
               sorted_by_x.begin() + mid,  sorted_by_x.begin() + right,
               buffer.begin(), [](const Point &a, const Point &b){ return a.y < b.y; });
    std::copy(buffer.begin(), buffer.begin() + n, sorted_by_x.begin() + left);

    // Build strip of points within sqrt(d) of mid line
    std::vector<Point> strip;
    double lim = std::sqrt(d);
    for (size_t i = left; i < right; ++i)
        if (std::abs(sorted_by_x[i].x - mid_x) <= lim)
            strip.push_back(sorted_by_x[i]);

    // Check strip points
    for (size_t i = 0; i < strip.size(); ++i)
        for (size_t j = i + 1; j < strip.size() && (strip[j].y - strip[i].y) <= lim; ++j)
            d = std::min(d, dist_sq(strip[i], strip[j]));

    return d;
}

inline double closestPair(const std::vector<Point> &points) {
    if (points.size() < 2) return 0.0;
    std::vector<Point> px = points;
    std::sort(px.begin(), px.end(), [](const Point &a, const Point &b){ return a.x < b.x; });
    std::vector<Point> buf(px.size());
    double best_sq = closest_pair_rec(px, buf, 0, px.size());
    return std::sqrt(best_sq);
}
