#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/// Perform an in‑place LU factorisation of an N×N matrix stored in row‑major
/// The result is stored in the same array A – the lower part contains L (unit diagonal),
/// the upper part contains U.
///
/// \param A  Reference to a vector of size N*N containing the matrix.
/// \param N  Matrix dimension.
inline void luFactorize(std::vector<double> &A, std::size_t N)
{
    // For static scheduling we keep the outer most loop single‑threaded
    // because subsequent stages depend on the current pivot row.
    for (std::size_t k = 0; k < N; ++k)
    {
        const double pivot = A[k * N + k];
        // Parallelise the eliminations for rows i > k
        #pragma omp parallel for schedule(static,64) private (pivot)
        for (std::size_t i = k + 1; i < N; ++i)
        {
            double *const row_i = &A[i * N];               // fast row pointer
            const double *const row_k = &A[k * N];         // pivot row

            // Compute the multiplier and store it in the L part
            const double factor = row_i[k] / pivot;
            row_i[k] = factor;                             // L(i,k)

            // Update the rest of the row (j = k+1 .. N-1)
            for (std::size_t j = k + 1; j < N; ++j)
            {
                row_i[j] -= factor * row_k[j];             // U(i,j)
            }
        }
    }
}
```

The implementation retains the exact mathematical behaviour, uses
`std::size_t` for indices, and exploits OpenMP to parallelise the
independent eliminations on rows `i > k`.  Row pointers are used to
minimise arithmetic overhead, and a static schedule with a chunk size
matching typical cache line boundaries helps keep the processor streams
efficient.

