#include <omp.h>

/* Multiply the matrix A by the vector x. Store the results in the vector y.
   A is an MxN matrix stored in row-major, x has N elements, and y has M elements.
   Example:
   input:  A = [[1, -1, 2], [0, -3, 1]]  x = [2, 1, 0]
   output: y = [1, -3]
*/
inline void gemv(std::vector<double> const& A,
                 std::vector<double> const& x,
                 std::vector<double> & y,
                 size_t M,
                 size_t N) noexcept
{
    // Defensive check: ensure containers have expected sizes
    // (Not strictly required for performance but protects against UB)
    if (A.size() < M * N || x.size() < N || y.size() < M)
        return;

    const double* __restrict a = A.data();
    const double* __restrict xv = x.data();
    double* __restrict yv = y.data();

    // Parallelize over rows with static scheduling to keep each thread busy
    #pragma omp parallel for schedule(static)
    for (long long i = 0; i < static_cast<long long>(M); ++i) {
        const double* arow = a + i * N;
        double sum = 0.0;
        // Unroll inner loop by 4 to reduce loop overhead and enable vectorization
        size_t j = 0;
        const size_t unroll = 4;
        const size_t limit = N - N % unroll;
        for (; j < limit; j += unroll) {
            sum += arow[j]   * xv[j];
            sum += arow[j+1] * xv[j+1];
            sum += arow[j+2] * xv[j+2];
            sum += arow[j+3] * xv[j+3];
        }
        for (; j < N; ++j) {
            sum += arow[j] * xv[j];
        }
        yv[i] = sum;
    }
}
