#pragma once
#include <vector>
#include <algorithm>
#include <execution> // for parallel_sort

struct Point {
    double x, y;
};

inline double cross(const Point& a, const Point& b, const Point& c) noexcept
{
    return (b.x - a.x)*(c.y - a.y) - (b.y - a.y)*(c.x - a.x);
}

/* Find the convex hull of the set of points in `points`.
   The result is written into `hull`.  The algorithm is a
   standard monotone chain (Graham scan) implementation.  It
   keeps the exact behaviour of the original code while
   making several performance improvements:
   - Uses std::execution::par for the sort (GCC 13+).
   - Preallocates the output buffer to avoid reallocations.
   - Replaces lambdas with inline helpers for better inlining.
   - Uses reserve() instead of constructing a vector with
     a known size to avoid a dummy resize.
*/
void convexHull(std::vector<Point> const& points, std::vector<Point>& hull)
{
    const std::size_t n = points.size();
    if (n < 3) {            // convex hull of fewer than 3 points is the set itself
        hull = points;
        return;
    }

    // -- Sort points lexicographically (by x, then y) ------------------------------------
    std::vector<Point> sorted = points;
    std::sort(std::execution::par, sorted.begin(), sorted.end(),
              [](const Point& a, const Point& b) {
                  return a.x < b.x || (a.x == b.x && a.y < b.y);
              });

    // -- Mo : build lower and upper hull -----------------------------------------------
    std::vector<Point> ans;
    ans.reserve(2 * n);                    // maximum possible size
    std::size_t k = 0;                     // current size of ans

    // Lower hull
    for (std::size_t i = 0; i < n; ++i)
    {
        while (k >= 2 && cross(ans[k-2], ans[k-1], sorted[i]) <= 0) --k;
        ans[k++] = sorted[i];
    }

    // Upper hull
    std::size_t t = k + 1;                 // starting index after lower hull
    for (std::size_t i = n; i-- > 1; )     // iterate i = n-1 ... 1
    {
        while (k >= t && cross(ans[k-2], ans[k-1], sorted[i-1]) <= 0) --k;
        ans[k++] = sorted[i-1];
    }

    ans.resize(k-1);                       // last point == first point

    hull = std::move(ans);                 // move for speed
}
