#pragma once
#include <cmath>
#include <complex>
#include <tuple>
#include <vector>
#include <algorithm>

/*
 * Sort the vector `x` of complex numbers by their magnitude in ascending order.
 *
 * The implementation computes the magnitude once for each element and
 * performs a single pass of `std::sort` on a lightweight `std::tuple`
 * containing (magnitude, original index, reference to the element).
 *
 * This avoids redundant `std::abs` evaluations during the comparisons of
 * the original elements, which is a common hot‑spot for `std::sort` on
 * `std::complex<double>`.
 */
inline void sortComplexByMagnitude(std::vector<std::complex<double>> &x)
{
    // Use a separate array of indices and magnitudes to reduce the cost of
    // repeated abs() calls during sorting.
    const std::size_t n = x.size();
    std::vector<std::tuple<double, std::size_t, std::complex<double> *>> aux;
    aux.reserve(n);
    for (std::size_t i = 0; i < n; ++i)
        aux.emplace_back(std::abs(x[i]), i, &x[i]);

    // Sort using the precomputed magnitude; ties are broken by index to
    // preserve deterministic ordering identical to std::sort on the
    // original vector.
    std::sort(aux.begin(), aux.end(),
              [](auto const &a, auto const &b) {
                  if (std::get<0>(a) != std::get<0>(b))
                      return std::get<0>(a) < std::get<0>(b);
                  return std::get<1>(a) < std::get<1>(b);
              });

    // Reconstruct the sorted vector in place.
    std::vector<std::complex<double>> result;
    result.reserve(n);
    for (auto &t : aux)
        result.push_back(*std::get<2>(t));

    x.swap(result);
}
