struct Element {
    std::size_t index;
    double value;
};

/* Compute z = alpha*x + y where x and y are sparse vectors.  
   z should already contain zeros for all indices that may be touched.
   The routine keeps the original behaviour but uses multi‑threaded
   parallelism for speed.  */
void sparseAxpy(double alpha,
                std::vector<Element> const& x,
                std::vector<Element> const& y,
                std::vector<double> &z)
{
    if (x.empty() && y.empty()) return;

    /* If the data set is tiny, serial execution is cheaper. */
    if (x.size() + y.size() <= 4'000) {
        std::size_t xi = 0, yi = 0;
        const std::size_t xs = x.size(), ys = y.size();
        while (xi < xs && yi < ys) {
            if (x[xi].index < y[yi].index) {
                z[x[xi].index] += alpha * x[xi].value;
                ++xi;
            } else if (x[xi].index > y[yi].index) {
                z[y[yi].index] += y[yi].value;
                ++yi;
            } else {
                z[x[xi].index] += alpha * x[xi].value + y[yi].value;
                ++xi;
                ++yi;
            }
        }
        while (xi < xs) { z[x[xi].index] += alpha * x[xi].value; ++xi; }
        while (yi < ys) { z[y[yi].index] += y[yi].value;      ++yi; }
        return;
    }

    /* Find split points in the y vector so that each thread gets roughly
       the same number of elements to process (and the corresponding
       portion of x).  */
    const std::size_t ysize = y.size();
    const std::size_t num_threads = std::min<std::size_t>(4, omp_get_max_threads());
    std::vector<std::size_t> y_split(num_threads + 1, 0);
    for (std::size_t t = 0; t <= num_threads; ++t) {
        y_split[t] = ysize * t / num_threads;
    }

    /* For each split point in y, find the corresponding split point in x
       by binary searching the first y index that is not less than the
       current x index.  */
    std::vector<std::size_t> x_split(num_threads + 1, 0);
    std::size_t xi_global = 0;
    for (std::size_t t = 0; t <= num_threads; ++t) {
        std::size_t next_y_idx = y_split[t];
        if (next_y_idx < ysize) {
            std::size_t key = y[next_y_idx].index;
            xi_global = std::lower_bound(
                x.begin() + xi_global, x.end(), key,
                [](Element const& e, std::size_t v){ return e.index < v; })
                - x.begin();
        }
        x_split[t] = xi_global;
    }

    /* Each thread processes a consecutive sub‑range of y and the
       corresponding sub‑range of x.  */
#pragma omp parallel for schedule(static,1)
    for (int t = 0; t < static_cast<int>(num_threads); ++t) {
        std::size_t y_start = y_split[t];
        std::size_t y_end   = y_split[t + 1];
        std::size_t x_start = x_split[t];
        std::size_t x_end   = x_split[t + 1];

        std::size_t xi = x_start, yi = y_start;
        const std::size_t xs = x_end, ys = y_end;
        while (xi < xs && yi < ys) {
            if (x[xi].index < y[yi].index) {
                z[x[xi].index] += alpha * x[xi].value;
                ++xi;
            } else if (x[xi].index > y[yi].index) {
                z[y[yi].index] += y[yi].value;
                ++yi;
            } else {
                z[x[xi].index] += alpha * x[xi].value + y[yi].value;
                ++xi;
                ++yi;
            }
        }
        while (xi < xs) { z[x[xi].index] += alpha * x[xi].value; ++xi; }
        while (yi < ys) { z[y[yi].index] += y[yi].value;          ++yi; }
    }
