/* Return true if the vector x contains the value `target`. Return false otherwise.
   Implemented with hand‑rolled SIMD checks for maximum speed on modern x86‑64.
   No change to the public API. */
inline bool contains(const std::vector<int>& x, int target) {
    const std::size_t n = x.size();
    if (n == 0) return false;

    // Broadcast target into an AVX2 register
    const __m256i vTarget = _mm256_set1_epi32(target);

    std::size_t i = 0;
    const std::size_t step = 8;   // 8 ints = 256 bits

    // Process 8 ints per loop iteration
    for (; i + step <= n; i += step) {
        const __m256i vec = _mm256_loadu_si256(reinterpret_cast<const __m256i*>(x.data() + i));
        const __m256i cmp = _mm256_cmpeq_epi32(vec, vTarget);
        if (_mm256_movemask_epi8(cmp) != 0) return true;
    }

    // Tail handling (4, 2, 1 elements)
    for (; i < n; ++i) {
        if (x[i] == target) return true;
    }

    return false;
}
