struct Point {
    double x, y;
};

// Inline helpers for speed
inline double sq(double v) { return v * v; }
inline double dist(const Point &a, const Point &b)
{
    double dx = b.x - a.x;
    double dy = b.y - a.y;
    return std::sqrt(dx * dx + dy * dy);
}

// Computes (B-A) x (C-A)
inline double cross(const Point &a, const Point &b, const Point &c)
{
    return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
}

/* Return the perimeter of the smallest convex polygon that contains all the points in the vector points. */
double convexHullPerimeter(std::vector<Point> const& points)
{
    std::size_t n = points.size();
    if (n < 3) return 0.0;

    // Make a copy for sorting
    std::vector<Point> pts = points;
    std::sort(pts.begin(), pts.end(),
              [](const Point &a, const Point &b) {
                  return a.x < b.x || (a.x == b.x && a.y < b.y);
              });

    // Upper bound on hull size is 2*n
    std::vector<Point> hull(2 * n);
    std::size_t k = 0;

    // Build lower hull
    for (std::size_t i = 0; i < n; ++i)
    {
        while (k >= 2 && cross(hull[k-2], hull[k-1], pts[i]) <= 0.0)
            --k;
        hull[k++] = pts[i];
    }

    // Build upper hull
    std::size_t t = k + 1;
    for (std::size_t i = n-1; i > 0; --i)
    {
        while (k >= t && cross(hull[k-2], hull[k-1], pts[i-1]) <= 0.0)
            --k;
        hull[k++] = pts[i-1];
    }

    hull.resize(k - 1);                     // last point same as first

    // Compute perimeter
    double per = 0.0;
    #pragma omp parallel for reduction(+:per) schedule(static)
    for (std::size_t i = 0; i < hull.size(); ++i)
    {
        const Point &a = hull[i];
        const Point &b = hull[(i + 1) % hull.size()];
        per += dist(a, b);
    }

    return per;
}
```
