 * The implementation uses a parallel reduction when available and
 * the standard library for sequential execution.
 *
 * @param x A non‑empty vector of `double`.
 * @return Index of the element whose distance from `M_PI` is minimal.
 */
inline size_t findClosestToPi(std::vector<double> const& x) {
    // Ensure the vector is not empty (undefined behaviour otherwise)
    if (x.empty()) {
        return std::size_t(-1);
    }

    const double pi = M_PI;
    size_t bestIndex = 0;
    double bestDiff = std::abs(x[0] - pi);

#if defined(_OPENMP) && !defined(__APPLE__) // some compilers define _OPENMP on macOS but do not support non‑serial reductions
#pragma omp parallel
    {
        size_t threadIndex = 0;
        double threadDiff = std::abs(x[0] - pi);

#pragma omp for nowait
        for (size_t i = 1; i < x.size(); ++i) {
            double d = std::abs(x[i] - pi);
            if (d < threadDiff) {
                threadDiff = d;
                threadIndex = i;
            }
        }

#pragma omp critical
        {
            if (threadDiff < bestDiff) {
                bestDiff = threadDiff;
                bestIndex = threadIndex;
            }
        }
    }
#else
    // Fallback to sequential code if OpenMP is not available
    for (size_t i = 1; i < x.size(); ++i) {
        const double d = std::abs(x[i] - pi);
        if (d < bestDiff) {
            bestDiff = d;
            bestIndex = i;
        }
    }
#endif

    return bestIndex;
}
