#pragma once
#include <vector>
#include <algorithm>
#include <cstring>
#include <omp.h>

/* Solve the linear system Ax=b for x.
   A is an NxN matrix in row-major. x and b have N elements.
   The function returns immediately if a pivot is zero, leaving x unchanged.
   Original behaviour is preserved; only internal layout and parallelisation
   have been changed for speed. */
inline void solveLinearSystem(const std::vector<double> &A,
                              const std::vector<double> &b,
                              std::vector<double> &x, size_t N)
{
    // Local copies – use raw arrays for speed
    std::vector<double> A_copy(A);
    std::vector<double> b_copy(b);

    for (size_t i = 0; i < N - 1; ++i) {
        const double pivot = A_copy[i * N + i];
        if (pivot == 0.0) return;            // singular

        const double inv_pivot = 1.0 / pivot;

        /* Eliminate rows below the pivot.
           Parallelise over the rows (j).  Each thread works on
           a separate row so the inner k‑loop can be vectorised by GCC. */
#pragma omp parallel for schedule(static)
        for (long long j = i + 1; j < static_cast<long long>(N); ++j) {
            const double factor = A_copy[j * N + i] * inv_pivot;
            double *row_j = A_copy.data() + j * N;
            const double *row_i = A_copy.data() + i * N;
            for (size_t k = i; k < N; ++k)
                row_j[k] -= factor * row_i[k];
            b_copy[j] -= factor * b_copy[i];
        }
    }

    // Back substitution – no parallelisation needed (sequential dependence)
    for (long long ii = static_cast<long long>(N) - 1; ii >= 0; --ii) {
        const size_t i = static_cast<size_t>(ii);
        double sum = 0.0;
        const double *row = A_copy.data() + i * N;
        for (size_t j = i + 1; j < N; ++j)
            sum += row[j] * x[j];
        x[i] = (b_copy[i] - sum) / row[i];
    }
}
```
This version keeps the functional behaviour unchanged while:

1. Copying the data into flat `std::vector`s to avoid extra bounds checks.
2. Using a raw pointer access pattern for inner loops which GCC can vectorise.
3. Parallelising the elimination of rows below the pivot with OpenMP.
4. Employing `inline` to encourage inlining by the compiler.

