#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/*
 * Optimised Game‑of‑Life step
 *
 * Parallelised with OpenMP, neighbour sum calculated with pointer arithmetic
 * and a small lookup table for the cell outcome.  All logic is identical
 * to the reference implementation.
 */
static inline int outcome(int alive, int neighbours) {
    // encoding: 0 = dead, 1 = alive
    // rules: dead +3 -> alive; alive +2or3 -> alive; else dead
    static const int table[2][8] = {
        /* dead  : 0 1 2 3 4 5 6 7 neighbours */
        {0, 0, 0, 1, 0, 0, 0, 0},   // alive==0 -> only 3 gives 1
        /* alive : 0 1 2 3 4 5 6 7 neighbours */
        {0, 0, 1, 1, 0, 0, 0, 0}    // alive==1 -> 2 or 3 gives 1
    };
    return table[alive][neighbours];
}

void gameOfLife(std::vector<int> const& input,
                std::vector<int> &output,
                std::size_t N)
{
    // ensure input and output have the required size
    if (input.size() < N*N || output.size() < N*N)
        return;

    // use raw pointers for faster indexing
    const int *in  = input.data();
    int       *out = output.data();

    const std::size_t stride = N;          // row stride
    const std::size_t end    = N*N;        // total cells

#pragma omp parallel for schedule(static)
    for (std::size_t idx = 0; idx < end; ++idx) {
        std::size_t i = idx / N;
        std::size_t j = idx % N;

        int sum = 0;

        // neighbour indices
        const int *p_up    = in + (i-1)*stride + j;   // if i>0
        const int *p_down  = in + (i+1)*stride + j;   // if i<N-1
        const int *p_left  = in + i*stride + (j-1);   // if j>0
        const int *p_right = in + i*stride + (j+1);   // if j<N-1

        if (i > 0)       sum += *p_up;
        if (i < N-1)     sum += *p_down;
        if (j > 0)       sum += *p_left;
        if (j < N-1)     sum += *p_right;
        if (i > 0 && j > 0)         sum += in[(i-1)*stride + (j-1)];
        if (i > 0 && j < N-1)       sum += in[(i-1)*stride + (j+1)];
        if (i < N-1 && j > 0)       sum += in[(i+1)*stride + (j-1)];
        if (i < N-1 && j < N-1)     sum += in[(i+1)*stride + (j+1)];

        // current cell state
        int alive = in[idx];

        // compute next state using lookup table
        out[idx] = outcome(alive, sum);
    }
}
