#pragma once
#include <vector>
#include <cstddef>
#include <xmmintrin.h>   // SSE intrinsics
#include <omp.h>

/*
 * Parallel blocked matrix multiplication (C = C + A * B).
 * A: M x K, B: K x N, C: M x N (row‑major).
 * Uses a cache‑friendly blocking strategy and SSE vectorization
 * to maximise performance on modern x86‑64 CPUs.
 *
 * NOTE: The function assumes that C already contains the correct
 * initial values.  It only adds the product of A and B to C.
 *
 * Keeps the original function signature for compatibility with the
 * harness.
 */
void gemm(std::vector<double> const& A,
          std::vector<double> const& B,
          std::vector<double>& C,
          size_t M, size_t K, size_t N)
{
    /* block size tuned for L1 cache (typical 32‑KB).  64 rows/cols is a good trade‑off. */
    constexpr size_t BLOCK = 64;

    /* Parallelise the outer two blocks (i‑block, k‑block). */
    #pragma omp parallel for collapse(2) schedule(static)
    for (size_t ii = 0; ii < M; ii += BLOCK)
    {
        for (size_t kk = 0; kk < K; kk += BLOCK)
        {
            /* minimum block dimensions (the last block can be smaller) */
            size_t iMax = std::min(ii + BLOCK, M);
            size_t kMax = std::min(kk + BLOCK, K);

            for (size_t i = ii; i < iMax; ++i)
            {
                for (size_t k = kk; k < kMax; ++k)
                {
                    double aik = A[i * K + k];

                    /* unroll j‑loop with SSE (4 doubles at a time) */
                    size_t j = 0;
                    for (; j + 3 < N; j += 4)
                    {
                        __m128d a1 = _mm_set1_pd(aik);
                        __m128d b1 = _mm_loadu_pd(&B[k * N + j]);
                        __m128d b2 = _mm_loadu_pd(&B[k * N + j + 2]);

                        __m128d c1 = _mm_loadu_pd(&C[i * N + j]);
                        __m128d c2 = _mm_loadu_pd(&C[i * N + j + 2]);

                        c1 = _mm_add_pd(c1, _mm_mul_pd(a1, b1));
                        c2 = _mm_add_pd(c2, _mm_mul_pd(a1, b2));

                        _mm_storeu_pd(&C[i * N + j],     c1);
                        _mm_storeu_pd(&C[i * N + j + 2], c2);
                    }

                    /* tail for remaining columns */
                    for (; j < N; ++j)
                    {
                        C[i * N + j] += aik * B[k * N + j];
                    }
                }
            }
        }
    }
}
