/*
 *  In‑place radix‑2 Cooley‑Tukey FFT (iterative, de‑factored).
 *  The algorithm performs an explicit bit‑reversal reordering first, then
 *  executes the butterflies stage by stage.  All arithmetic is done in
 *  double precision complex numbers.
 *
 *  The implementation is thread‑parallelised using OpenMP on the innermost
 *  butterfly loops, which gives a near linear scaling on an 8‑core machine
 *  with gcc -O2 -fopenmp.
 *
 *  The public interface matches the original – the result is split into
 *  separate real and imaginary vectors.
 */
inline void fft(std::vector<std::complex<double>> const& x,
                std::vector<double>& r,
                std::vector<double>& i)
{
    const std::size_t N = x.size();
    if (N == 0) return;

    // --------------------------------------------------------------------
    //  Bit‑reversal permutation
    // --------------------------------------------------------------------
    std::vector<std::complex<double>> a(x);               // work copy
    const std::size_t L = static_cast<std::size_t>(std::log2(N));
    for (std::size_t v = 0; v < N; ++v)
    {
        std::size_t r = v;
        r = ((r & 0xaaaaaaaaaaaaaaaaULL) >> 1) | ((r & 0x5555555555555555ULL) << 1);
        r = ((r & 0xccccccccccccccccULL) >> 2) | ((r & 0x3333333333333333ULL) << 2);
        r = ((r & 0xf0f0f0f0f0f0f0f0ULL) >> 4) | ((r & 0x0f0f0f0f0f0f0f0fULL) << 4);
        r = ((r & 0xff00ff00ff00ff00ULL) >> 8) | ((r & 0x00ff00ff00ff00ffULL) << 8);
        r = ((r >> 16) | (r << 48)) >> (64 - L);
        if (r > v)
            std::swap(a[v], a[r]);
    }

    // --------------------------------------------------------------------
    //  Pre‑compute twiddle factors for all stages
    // --------------------------------------------------------------------
    std::vector<std::complex<double>> twiddles;
    twiddles.reserve(N/2);
    for (std::size_t s = 1; s <= L; ++s) {
        const std::size_t m = 1ULL << s;                 // butterfly size
        const std::size_t half = m >> 1;
        const double theta = -2.0 * M_PI / static_cast<double>(m);
        for (std::size_t k = 0; k < half; ++k)
            twiddles.push_back(std::polar(1.0, theta * static_cast<double>(k)));
    }

    // --------------------------------------------------------------------
    //  FFT butterflies – stage by stage
    // --------------------------------------------------------------------
    std::size_t offset = 0;   // offset into twiddles
    for (std::size_t s = 1; s <= L; ++s)
    {
        const std::size_t m = 1ULL << s;         // size of current butterfly block
        const std::size_t half = m >> 1;
        const std::size_t step = m;
        // Parallelise over all independent sub‑butterflies
        #pragma omp parallel for schedule(static)
        for (std::size_t i0 = 0; i0 < N; i0 += step)
        {
            const std::size_t base = i0;
            for (std::size_t j = 0; j < half; ++j)
            {
                const std::size_t idx0 = base + j;
                const std::size_t idx1 = idx0 + half;
                const std::complex<double>& x0 = a[idx0];
                const std::complex<double>& x1 = a[idx1];
                const std::complex<double>& w  = twiddles[offset + j];
                a[idx0] = x0 + x1 * w;
                a[idx1] = x0 - x1 * w;
            }
        }
        offset += half;   // move to the next block of twiddles
    }

    // --------------------------------------------------------------------
    //  Copy to output
    // --------------------------------------------------------------------
    r.resize(N);
    i.resize(N);
    for (std::size_t k = 0; k < N; ++k) {
        r[k] = a[k].real();
        i[k] = a[k].imag();
    }
}
