#pragma once
#include <vector>
#include <algorithm>
#include <cstring>
#include <omp.h>

struct Result {
   int startTime, duration;
   float value;
};

static const size_t PARALLEL_THRESHOLD = 1 << 14; // 16K elements

// Merge helper that merges two consecutive sorted ranges [l, m) and [m, r)
static void merge_range(std::vector<Result> &tmp,
                       const std::vector<Result> &data,
                       size_t l, size_t m, size_t r) {
    size_t i = l, j = m, k = l;
    while (i < m && j < r) {
        if (data[i].startTime <= data[j].startTime)
            tmp[k++] = data[i++];
        else
            tmp[k++] = data[j++];
    }
    while (i < m) tmp[k++] = data[i++];
    while (j < r) tmp[k++] = data[j++];
}

// Recursive parallel merge sort.
// The sorted result is written into 'tmp', then copied back to 'data'.
static void parallel_merge_sort(std::vector<Result> &data, std::vector<Result> &tmp,
                                 size_t l, size_t r) {
    if (r - l <= 1) {
        if (l < r) tmp[l] = data[l];
        return;
    }

    // If the subproblem is small, serial sort.
    if (r - l < PARALLEL_THRESHOLD) {
        std::sort(data.begin() + l, data.begin() + r, [](const Result &a, const Result &b) {
            return a.startTime < b.startTime;
        });
        std::copy(data.begin() + l, data.begin() + r, tmp.begin() + l);
        return;
    }

    size_t m = (l + r) / 2;

    // Sort left and right halves in parallel.
    #pragma omp task shared(data, tmp)
    parallel_merge_sort(data, tmp, l, m);

    #pragma omp task shared(data, tmp)
    parallel_merge_sort(data, tmp, m, r);

    #pragma omp taskwait

    // Merge the two sorted halves.
    merge_range(tmp, data, l, m, r);
}

// Public API – keeps the same signature as the original.
inline void sortByStartTime(std::vector<Result> &results) {
    if (results.empty()) return;
    std::vector<Result> tmp(results.size());

    #pragma omp parallel
    {
        #pragma omp single
        parallel_merge_sort(results, tmp, 0, results.size());
    }

    results.swap(tmp); // now 'results' holds the sorted data
}
