/* ----------------------------------------------------
   In‑place radix‑2 Cooley‑Tukey FFT.
   Size must be a power of two.  Exact same semantics
   as the original implementation.
   ---------------------------------------------------- */
static void fft_radix2(std::vector<std::complex<double>>& x)
{
    const std::size_t N = x.size();
    std::size_t k = N;
    std::size_t n;
    const double theta = M_PI / static_cast<double>(N);
    std::complex<double> phi = std::complex<double>(std::cos(theta), -std::sin(theta));
    std::complex<double> T;

    /* iterative butterfly stage */
    while (k > 1) {
        n = k;
        k >>= 1;
        phi = phi * phi;           /* square twiddle factor for next stage */
        T   = std::complex<double>(1.0, 0.0);

        /* The outer loop is short (log2(N) iterations).  The inner loop
           processes O(N) elements, so we parallelise on that. */
#pragma omp parallel for schedule(static)
        for (std::size_t l = 0; l < k; ++l) {
            for (std::size_t a = l; a < N; a += n) {
                std::size_t b = a + k;
                std::complex<double> t = x[a] - x[b];
                x[a] += x[b];
                x[b] = t * T;
            }
            T *= phi;
        }
    }

    /* ---------- bit‑reversal permutation ---------- */
    const unsigned int m = static_cast<unsigned int>(std::log2(static_cast<double>(N)));
    /* We compute a reverse‑bit table once on the first call
       and reuse it locally.  The table holds the reverse of the
       lower m bits of each index. */
    static std::vector<std::uint32_t> rev_table = []{
        std::vector<std::uint32_t> tbl(1 << 16);
        for (std::uint32_t i = 0; i < tbl.size(); ++i) {
            std::uint32_t x = i;
            x = ((x & 0x5555u) << 1) | ((x & 0xAAAAu) >> 1);
            x = ((x & 0x3333u) << 2) | ((x & 0xCCCCu) >> 2);
            x = ((x & 0x0F0Fu) << 4) | ((x & 0xF0F0u) >> 4);
            x = ((x & 0x00FFu) << 8) | ((x & 0xFF00u) >> 8);
            tbl[i] = x >> (16 - m);
        }
        return tbl;
    }();

    /* Perform swaps only once, no data races because each
       index is swapped only by the thread that sees the lower
       partner (b > a condition). */
#pragma omp parallel for schedule(static)
    for (std::size_t a = 0; a < N; ++a) {
        std::size_t b = rev_table[a];
        if (b > a) std::swap(x[a], x[b]);
    }
}

/* ----------------------------------------------------
   In‑place inverse FFT, identical to original semantics.
   ---------------------------------------------------- */
inline void ifft(std::vector<std::complex<double>>& x)
{
    /* Conjugation + forward FFT + conjugation + scaling */
#pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < x.size(); ++i)
        x[i] = std::conj(x[i]);

    fft_radix2(x);

#pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < x.size(); ++i)
        x[i] = std::conj(x[i]);

    const double invN = 1.0 / static_cast<double>(x.size());
#pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < x.size(); ++i)
        x[i] *= invN;
}
